import{_ as n,o as a,c as e,S as t}from"./chunks/framework.C6RQlTYc.js";const b=JSON.parse('{"title":"面试官问：Multi-Agent 多智能体系统","description":"","frontmatter":{},"headers":[],"relativePath":"面试官问/17ai/q_ai_19-multi_agent.md","filePath":"面试官问/17ai/q_ai_19-multi_agent.md","lastUpdated":1778207238000}'),i={name:"面试官问/17ai/q_ai_19-multi_agent.md"};function l(p,s,r,g,c,d){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="面试官问-multi-agent-多智能体系统" tabindex="-1">面试官问：Multi-Agent 多智能体系统 <a class="header-anchor" href="#面试官问-multi-agent-多智能体系统" aria-label="Permalink to &quot;面试官问：Multi-Agent 多智能体系统&quot;">​</a></h1><blockquote><p>📚 参考：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_29-multi_agent.html">Multi-Agent 系统</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_24-agent.html">AI Agent 智能体</a> | <a href="/FE-prepare-interview/直击概念/17ai/s_ai_27-mcp.html">MCP 协议</a></p></blockquote><h2 id="_1-multi-agent-系统和单-agent-的根本区别-什么时候该用多-agent" tabindex="-1">1. Multi-Agent 系统和单 Agent 的根本区别？什么时候该用多 Agent？ <a class="header-anchor" href="#_1-multi-agent-系统和单-agent-的根本区别-什么时候该用多-agent" aria-label="Permalink to &quot;1. Multi-Agent 系统和单 Agent 的根本区别？什么时候该用多 Agent？&quot;">​</a></h2><p><strong>考察点</strong>：是否理解单 Agent 的局限性，能否判断什么时候需要多 Agent 架构。</p><details class="details custom-block"><summary>详细信息</summary><p><strong>核心回答</strong>：</p><p>单 Agent 就像一个全能员工——理论上什么都能做，但复杂任务会出现：</p><ul><li><strong>上下文溢出</strong>：规划 + 推理 + 工具调用 + 结果验证全部挤在一个上下文窗口</li><li><strong>角色冲突</strong>：同一模型难以在&quot;生成代码&quot;和&quot;审查代码&quot;之间自由切换</li><li><strong>单点故障</strong>：Agent 出错则整个任务失败</li></ul><p>Multi-Agent 则像一支团队——每个 Agent 有专门角色和工具，通过协作完成复杂任务。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>单 Agent 方案：</span></span>
<span class="line"><span>用户 → [一个大而全的 Agent] → 结果</span></span>
<span class="line"><span>       ✗ 上下文不足、角色混淆、容易出错</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Multi-Agent 方案：</span></span>
<span class="line"><span>用户 → 编排器（拆解任务）</span></span>
<span class="line"><span>         ├→ Agent A（专业分析）</span></span>
<span class="line"><span>         ├→ Agent B（执行操作）  </span></span>
<span class="line"><span>         ├→ Agent C（验证结果）</span></span>
<span class="line"><span>         └→ Agent D（汇总输出）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><p><strong>决策矩阵</strong>：</p><table><thead><tr><th>场景</th><th style="text-align:center;">推荐</th><th>原因</th></tr></thead><tbody><tr><td>简单问答</td><td style="text-align:center;">单 Agent</td><td>直接、快速</td></tr><tr><td>需要多工具协作</td><td style="text-align:center;">单 Agent + Function Calling</td><td>工具调用本身不冲突</td></tr><tr><td>需要多角色（写+审+改）</td><td style="text-align:center;">Multi-Agent</td><td>角色隔离避免偏见</td></tr><tr><td>大规模代码生成</td><td style="text-align:center;">Multi-Agent</td><td>模块化拆分、并行处理</td></tr><tr><td>需要多轮验证/辩论</td><td style="text-align:center;">Multi-Agent</td><td>相互校验提高质量</td></tr></tbody></table></details><h2 id="_2-常见的-multi-agent-编排模式有哪些-各适合什么场景" tabindex="-1">2. 常见的 Multi-Agent 编排模式有哪些？各适合什么场景？ <a class="header-anchor" href="#_2-常见的-multi-agent-编排模式有哪些-各适合什么场景" aria-label="Permalink to &quot;2. 常见的 Multi-Agent 编排模式有哪些？各适合什么场景？&quot;">​</a></h2><details class="details custom-block"><summary>详细信息</summary><p><strong>四种核心模式</strong>：</p><p><strong>1. 顺序串行</strong>：A → B → C，流水线式</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>需求分析 Agent → 方案设计 Agent → 代码生成 Agent → 审查 Agent</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>适合：流程固定、阶段分明的任务（如标准开发流程）</p><p><strong>2. 路由分发</strong>：根据任务类型分给不同 Agent</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户提问 → 路由器</span></span>
<span class="line"><span>    ├→ 前端 Agent（React/Vue 问题）</span></span>
<span class="line"><span>    ├→ 后端 Agent（API/DB 问题）</span></span>
<span class="line"><span>    └→ DevOps Agent（部署相关）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>适合：多领域知识覆盖（客服系统）</p><p><strong>3. 层级管理</strong>：管理 Agent 协调多个执行 Agent</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>管理 Agent（任务拆解+分配+验证）</span></span>
<span class="line"><span>    ├→ 子 Agent 1 → 返回结果</span></span>
<span class="line"><span>    ├→ 子 Agent 2 → 返回结果</span></span>
<span class="line"><span>    └→ 子 Agent 3 → 返回结果</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    管理 Agent 汇总 + 验证</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>适合：复杂任务需要全局视图和结果把控</p><p><strong>4. 协作辩论</strong>：多 Agent 平等对话达成共识</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>Agent A：我建议方案 X，因为...</span></span>
<span class="line"><span>Agent B：方案 X 有 Y 问题，考虑方案 Z</span></span>
<span class="line"><span>Agent C：折中，方案 X 改进 + 方案 Z 优点</span></span>
<span class="line"><span>→ 达成共识</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>适合：需要多视角评估的关键决策（架构评审、安全审计）</p></details><h2 id="_3-前端场景中-multi-agent-的典型应用" tabindex="-1">3. 前端场景中 Multi-Agent 的典型应用？ <a class="header-anchor" href="#_3-前端场景中-multi-agent-的典型应用" aria-label="Permalink to &quot;3. 前端场景中 Multi-Agent 的典型应用？&quot;">​</a></h2><details class="details custom-block"><summary>详细信息</summary><p><strong>1. 全栈开发 Agent 团队</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户：&quot;做一个用户管理页面，支持列表+搜索+分页+新增&quot;</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>需求分析 Agent → 提取业务要点</span></span>
<span class="line"><span>UI Agent → 生成组件结构 → 生成 Vue/React 代码  </span></span>
<span class="line"><span>API Agent → 生成接口定义和 mock</span></span>
<span class="line"><span>测试 Agent → 分析代码 → 生成测试用例</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p><strong>2. 代码 CR Agent 系统</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>代码提交</span></span>
<span class="line"><span>    ├→ 性能审查 Agent → 检查渲染优化/memo使用</span></span>
<span class="line"><span>    ├→ 安全审查 Agent → 检查 XSS/注入风险</span></span>
<span class="line"><span>    ├→ 可访问性 Agent → 检查 a11y 规范</span></span>
<span class="line"><span>    └→ 风格审查 Agent → 检查 ESLint/StyleLint</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>    汇总 Agent → 生成 CR 报告</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>3. 智能客服路由</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>用户问题</span></span>
<span class="line"><span>    ├→ 简单 FAQ（直接回答，无需 Agent）</span></span>
<span class="line"><span>    ├→ 查询类（查订单/查物流 Agent）</span></span>
<span class="line"><span>    ├→ 故障类（诊断 Agent → 需要时升级人工）</span></span>
<span class="line"><span>    └→ 投诉类（安抚 Agent + 转人工 Agent）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div></details><h2 id="_4-multi-agent-的核心挑战是什么" tabindex="-1">4. Multi-Agent 的核心挑战是什么？ <a class="header-anchor" href="#_4-multi-agent-的核心挑战是什么" aria-label="Permalink to &quot;4. Multi-Agent 的核心挑战是什么？&quot;">​</a></h2><details class="details custom-block"><summary>详细信息</summary><ul><li><strong>协调成本</strong>：Agent 数量 ↑ 通信成本指数级上升</li><li><strong>成本控制</strong>：每次对话可能 10+ 次 LLM 调用</li><li><strong>幻觉放大</strong>：每个 Agent 都可能出错，链条越长错误累积越严重</li><li><strong>循环死锁</strong>：两个 Agent 陷入无效的互相纠正循环</li><li><strong>延迟</strong>：多个 Agent 串行执行导致用户等待时间长</li></ul><p><strong>缓解策略</strong>：并行执行独立任务、设置最大轮次上限、关键节点加入人工审核。</p></details><blockquote><p>来源：<a href="/FE-prepare-interview/直击概念/17ai/s_ai_29-multi_agent.html">Multi-Agent 系统概念讲解</a></p></blockquote>`,12)])])}const o=n(i,[["render",l]]);export{b as __pageData,o as default};
